package com.school.controller;
import com.school.entity.*; import com.school.enums.RoleName; import com.school.repository.*; import jakarta.transaction.Transactional; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.stereotype.Controller; import org.springframework.ui.Model; import org.springframework.web.bind.annotation.*;
@Controller public class AuthController { private final UserRepository users; private final StudentRepository students; private final PasswordEncoder passwords; public AuthController(UserRepository users,StudentRepository students,PasswordEncoder passwords){this.users=users;this.students=students;this.passwords=passwords;} @GetMapping("/login") String login(){return "login/index";} @GetMapping("/signup") String signup(){return "login/signup";} @PostMapping("/signup") @Transactional String create(@RequestParam String firstName,@RequestParam String lastName,@RequestParam String registrationNumber,@RequestParam String email,@RequestParam String username,@RequestParam String password,@RequestParam String phone,Model model){if(users.existsByUsername(username)||users.existsByEmail(email)||students.existsByRegistrationNumber(registrationNumber)){model.addAttribute("error","That username, email, or registration number is already in use.");return "login/signup";}if(password.length()<8){model.addAttribute("error","Use a password with at least 8 characters.");return "login/signup";}User user=users.save(new User(username,email,passwords.encode(password),firstName+" "+lastName,RoleName.STUDENT));Student student=new Student(registrationNumber,firstName,lastName,email);student.setPhone(phone);student.setUser(user);students.save(student);return "redirect:/login?registered";} @GetMapping("/403") String denied(){return "error/403";} }
